var e=[{id:`L2_1`,type:`dialog`,speaker:`GAEUN_NPC_FOOLSDAY_NULL`,text:{KOREA:`사장님이 선생님이란 건 모두에게 비밀로 할게요. 그러니까 이제 두 번 다시는... 저를 두고 떠나지 말아 주세요.`,JPN:`社長が先生だってことはみんなに内緒にします。だからもう二度と……私を置いていかないでください。`,ENG:`I won't tell anyone that you're my Teacher. So, please... don't ever leave me again.`,TWN:`老闆是老師這件事，我會對大家保密的。所以請不要……再丟下我離開。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GAEUN_NPC_FOOLSDAY_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`GAEUN_NPC_FOOLSDAY_NULL`,text:{KOREA:`선생님과 함께할 수 있다면...... 그 외엔 아무것도 바라지 않아요.`,JPN:`先生と一緒にいられるなら……他には何も要りません。`,ENG:`I don't want anything, so long as I can be with you.`,TWN:`只要能和老師一起……其他的我什麼都不要了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GAEUN_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};